/**
 * @fileoverview CalendarView helpers — pure utility functions.
 *
 * Date arithmetic, formatting, comparison, range utilities,
 * and event-color cycling.  No side-effects, no DOM access.
 *
 * @module module/CalendarView/helpers
 */

import { EVENT_COLORS, DAY_MS } from './constants.js';

// ── Formatting ──────────────────────────────────

/**
 * Zero-pad a number to the given length.
 *
 * @param {number} n
 * @param {number} [len=2]
 * @returns {string}
 */
export function pad(n, len = 2) {
    return String(n).padStart(len, '0');
}

/**
 * Format a Date to "HH:MM".
 *
 * @param {Date} d
 * @returns {string}
 */
export function formatTime(d) {
    return `${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

// ── Date arithmetic ─────────────────────────────

/**
 * Return midnight of the given date (local).
 *
 * @param {Date} d
 * @returns {Date}
 */
export function startOfDay(d) {
    return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}

/**
 * Return the start-of-week for the given date.
 *
 * @param {Date}   d
 * @param {number} [weekStartsOn=0] — 0 = Sun, 1 = Mon
 * @returns {Date}
 */
export function startOfWeek(d, weekStartsOn = 0) {
    const day = d.getDay();
    const diff = (day - weekStartsOn + 7) % 7;
    return new Date(d.getFullYear(), d.getMonth(), d.getDate() - diff);
}

/**
 * Add (or subtract) `n` days to a date.
 *
 * @param {Date}   d
 * @param {number} n
 * @returns {Date}
 */
export function addDays(d, n) {
    return new Date(d.getFullYear(), d.getMonth(), d.getDate() + n);
}

/**
 * Number of days in a month.
 *
 * @param {number} y — full year
 * @param {number} m — 0-based month
 * @returns {number}
 */
export function daysInMonth(y, m) {
    return new Date(y, m + 1, 0).getDate();
}

// ── Comparison & range ──────────────────────────

/**
 * Test whether two dates represent the same calendar day.
 *
 * @param {Date|null} a
 * @param {Date|null} b
 * @returns {boolean}
 */
export function sameDay(a, b) {
    if (!a || !b) return false;
    return a.getFullYear() === b.getFullYear() &&
        a.getMonth() === b.getMonth() &&
        a.getDate() === b.getDate();
}

/**
 * Check whether `date` falls within a range starting at `start`
 * for `numDays` consecutive days.
 *
 * @param {Date}   date
 * @param {Date}   start
 * @param {number} numDays
 * @returns {boolean}
 */
export function isDateInRange(date, start, numDays) {
    const d = startOfDay(date).getTime();
    const s = startOfDay(start).getTime();
    const e = s + numDays * DAY_MS;
    return d >= s && d < e;
}

// ── Event helpers ───────────────────────────────

/** Cycling colour index (module-scoped). */
let colorIdx = 0;

/**
 * Return the next colour from the palette (cycling).
 *
 * @returns {string}
 */
export function nextColor() {
    return EVENT_COLORS[colorIdx++ % EVENT_COLORS.length];
}

/**
 * Normalise a raw event object (fill id, dates, colour).
 *
 * @param {object}   ev
 * @param {Function} hashFn — `razyui.hash`
 * @returns {object}
 */
export function normalizeEvent(ev, hashFn) {
    return {
        ...ev,
        id: ev.id || hashFn(7),
        title: ev.title || 'Untitled',
        start: ev.start instanceof Date ? ev.start : new Date(ev.start),
        end: ev.end instanceof Date ? ev.end : new Date(ev.end),
        color: ev.color || nextColor(),
    };
}

/**
 * Return events whose span overlaps the given calendar day.
 *
 * @param {Array}  events
 * @param {Date}   date
 * @returns {Array}
 */
export function getEventsForDay(events, date) {
    const dayStart = startOfDay(date).getTime();
    const dayEnd = dayStart + DAY_MS;
    return events.filter(ev => {
        const s = ev.start.getTime();
        const e = ev.end.getTime();
        return s < dayEnd && e > dayStart;
    });
}

/**
 * Allocate non-overlapping horizontal lanes for multi-day bars.
 *
 * Each bar object must have `{ startCol, endCol }`. This function
 * assigns a `.lane` property (0-based) and returns the total
 * number of lanes used.
 *
 * @param {Array} bars
 * @returns {number}
 */
export function allocateBarLanes(bars) {
    bars.sort((a, b) => a.startCol - b.startCol || (b.endCol - b.startCol) - (a.endCol - a.startCol));
    const laneEnds = [];
    for (const bar of bars) {
        let placed = false;
        for (let i = 0; i < laneEnds.length; i++) {
            if (laneEnds[i] <= bar.startCol) {
                laneEnds[i] = bar.endCol;
                bar.lane = i;
                placed = true;
                break;
            }
        }
        if (!placed) {
            bar.lane = laneEnds.length;
            laneEnds.push(bar.endCol);
        }
    }
    return laneEnds.length;
}

/**
 * Format an event's duration as a human-readable string.
 *
 * @param {Date} startDate
 * @param {Date} endDate
 * @returns {string}
 */
export function formatDuration(startDate, endDate) {
    const diffMs = endDate - startDate;
    const diffMin = Math.round(diffMs / 60000);
    if (diffMin >= 1440) {
        const days = Math.floor(diffMin / 1440);
        const remH = Math.floor((diffMin % 1440) / 60);
        return remH > 0 ? `${days}d ${remH}h` : `${days}d`;
    }
    if (diffMin < 60) return `${diffMin}min`;
    if (diffMin % 60 === 0) return `${diffMin / 60}h`;
    return `${Math.floor(diffMin / 60)}h ${diffMin % 60}min`;
}
