/**
 * @fileoverview CalendarView constants — month/day names, default config, colors.
 * @module module/CalendarView/constants
 */

import { MONTHS as _MONTHS, MONTHS_SHORT as _MONTHS_SHORT } from '../shared/tokens/locale.js';
import { ICON_CHEVRON_PREV, ICON_CHEVRON_NEXT, ICON_CLOSE_14 } from '../shared/tokens/icons.js';
import { defineParts } from '../shared/definePart.js';

// ── Month & day names ───────────────────────────

/** Full month names. */
export const MONTHS = _MONTHS;

/** Short month names. */
export const MONTHS_SHORT = _MONTHS_SHORT;

/** Short weekday names. */
export const WEEKDAYS_SHORT = Object.freeze(['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']);

// ── Default configuration ───────────────────────

/** Default configuration values. */
export const DEFAULTS = Object.freeze({
    view: 'month',
    date: null,               // resolved to new Date() at runtime
    events: [],
    weekStartsOn: 0,
    dayStartHour: 0,
    dayEndHour: 24,
});

// ── Magic numbers ───────────────────────────────

/** Milliseconds in a single day. */
export const DAY_MS = 86400000;

/** Max single-day event chips to show before collapsing. */
export const MAX_VISIBLE_CHIPS = 3;

/** Height in px allocated per multi-day bar lane. */
export const BAR_LANE_HEIGHT = 20;

/** Timer interval in ms for current-time indicator refresh. */
export const NOW_LINE_INTERVAL = 60000;

/** Default scroll target hour for week / day view. */
export const SCROLL_TARGET_HOUR = 8;

// ── Event palette ───────────────────────────────

/** Default cycling palette for event colors. */
export const EVENT_COLORS = Object.freeze([
    'hsl(216, 72%, 56%)', // blue
    'hsl(145, 55%, 42%)', // green
    'hsl(28, 80%, 52%)',  // orange
    'hsl(270, 55%, 56%)', // purple
    'hsl(0, 65%, 55%)',   // red
    'hsl(175, 55%, 40%)', // teal
    'hsl(45, 80%, 48%)',  // amber
    'hsl(330, 55%, 52%)', // pink
]);

// ── SVG icons ───────────────────────────────────

/** Chevron-left SVG for prev button. */
export const ICON_PREV = ICON_CHEVRON_PREV;

/** Chevron-right SVG for next button. */
export const ICON_NEXT = ICON_CHEVRON_NEXT;

/** Close (×) SVG for popup. */
export const ICON_CLOSE = ICON_CLOSE_14;

