/**
 * @fileoverview CalendarView CRUD feature — lazy-loadable event management.
 *
 * Provides:
 *   - Add event       (double-click empty slot / "+" button)
 *   - Edit event      (double-click existing event)
 *   - Delete event    (click delete button on popup)
 *   - AJAX integration (submit to backend via Dialog + AjaxForm)
 *   - Event type plugins (custom popup content per event type)
 *
 * Install via `installCrud(ctx)` — called from CalendarView constructor
 * when `config.crud` is truthy.  Lazy-loaded via:
 *   `await razyui.load('CalendarView')` then the CRUD installer runs if
 *   config.crud is set.
 *
 * Config shape:
 * ```
 * crud: {
 *     addUrl:    '/api/events',            // POST endpoint
 *     editUrl:   '/api/events/:id',        // PUT endpoint (:id replaced)
 *     deleteUrl: '/api/events/:id',        // DELETE endpoint (:id replaced)
 *     headers:   {},                        // extra fetch headers
 *     dialogSize:'md',                      // Dialog size preset
 *
 *     // Optional custom content builders (return HTML string or Element)
 *     renderAddContent:  (date, ctx) => ...,
 *     renderEditContent: (event, ctx) => ...,
 *
 *     // Event type definitions — plugins for typed event creation / editing
 *     eventTypes: [
 *         { type: 'meeting', label: 'Meeting',  color: '#4285f4',
 *           renderContent: (event, mode) => ... },
 *         { type: 'task',    label: 'Task',      color: '#0b8043',
 *           renderContent: (event, mode) => ... },
 *     ],
 *
 *     // Callbacks (sync or async — async supported for AJAX workflows)
 *     onBeforeAdd:    (data, ctrl) => ...,     // return false to cancel; may return Promise
 *     onAfterAdd:     (event, response) => {}, // may return Promise
 *     onBeforeEdit:   (data, ctrl) => ...,     // return false to cancel; may return Promise
 *     onAfterEdit:    (event, response) => {}, // may return Promise
 *     onBeforeDelete: (event, ctrl) => ...,    // return false to cancel; may return Promise
 *     onAfterDelete:  (event, response) => {},
 *     onError:        (errors, response) => {},
 *
 *     // Popup content transform — post-process rendered content
 *     transformContent: (contentEl, event, mode) => {},
 * }
 * ```
 *
 * @module module/CalendarView/features/crud
 */

import { ICON_CLOSE, PART } from '../constants.js';
import razyui from '../../../index.js';
import Icons from '../../Icons.js';
import DatePicker from '../../DatePicker/index.js';
import Combobox from '../../Combobox/index.js';

// ── SVG icons for CRUD UI ───────────────────────

const ICON_ADD = Icons.svg('plus', { size: 14, strokeWidth: 1.8 });
const ICON_EDIT = Icons.svg('square-pen', { size: 14, strokeWidth: 1.4 });
const ICON_DELETE = Icons.svg('trash-2', { size: 14, strokeWidth: 1.4 });

// ── Default form content builders ───────────────

/**
 * Build default "Add Event" form HTML.
 * @param {Date}   date      — clicked slot date
 * @param {Object} crudCfg   — crud config
 * @returns {string}
 */
function defaultAddContent(date, crudCfg, endDate) {
    const d = date;
    const dateStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    const startTime = `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;

    let endDateStr, endTimeStr;
    if (endDate) {
        endDateStr = `${endDate.getFullYear()}-${String(endDate.getMonth() + 1).padStart(2, '0')}-${String(endDate.getDate()).padStart(2, '0')}`;
        endTimeStr = `${String(endDate.getHours()).padStart(2, '0')}:${String(endDate.getMinutes()).padStart(2, '0')}`;
    } else {
        endDateStr = dateStr;
        const hour = d.getHours();
        endTimeStr = `${String(Math.min(hour + 1, 23)).padStart(2, '0')}:00`;
    }

    let typeSelect = '';
    if (crudCfg.eventTypes?.length) {
        const opts = crudCfg.eventTypes.map(
            t => `<option value="${t.type}">${t.label}</option>`
        ).join('');
        typeSelect = `
            <label class="form-label">
                <span>Type</span>
                <select name="type">${opts}</select>
            </label>`;
    }

    return `
        <form method="POST">
            ${typeSelect}
            <label class="form-label">
                <span>Title</span>
                <input type="text" name="title" placeholder="Event title" required autocomplete="off"/>
            </label>
            <div class="form-row">
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>Start Date</span>
                    <input type="text" name="date" value="${dateStr}" data-datepicker="date"/>
                </label>
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>Start Time</span>
                    <input type="text" name="startTime" value="${startTime}" data-datepicker="time"/>
                </label>
            </div>
            <div class="form-row">
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>End Date</span>
                    <input type="text" name="endDate" value="${endDateStr}" data-datepicker="date"/>
                </label>
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>End Time</span>
                    <input type="text" name="endTime" value="${endTimeStr}" data-datepicker="time"/>
                </label>
            </div>
            <label class="form-label">
                <span>Description</span>
                <textarea name="description" rows="3" placeholder="Optional description"></textarea>
            </label>
        </form>`;
}

/**
 * Build default "Edit Event" form HTML.
 * @param {Object} event     — normalised event object
 * @param {Object} crudCfg   — crud config
 * @returns {string}
 */
function defaultEditContent(event, crudCfg) {
    const s = event.start;
    const e = event.end;
    const dateStr = `${s.getFullYear()}-${String(s.getMonth() + 1).padStart(2, '0')}-${String(s.getDate()).padStart(2, '0')}`;
    const endDateStr = `${e.getFullYear()}-${String(e.getMonth() + 1).padStart(2, '0')}-${String(e.getDate()).padStart(2, '0')}`;
    const startTime = `${String(s.getHours()).padStart(2, '0')}:${String(s.getMinutes()).padStart(2, '0')}`;
    const endTime = `${String(e.getHours()).padStart(2, '0')}:${String(e.getMinutes()).padStart(2, '0')}`;

    let typeSelect = '';
    if (crudCfg.eventTypes?.length) {
        const opts = crudCfg.eventTypes.map(
            t => `<option value="${t.type}"${t.type === event.type ? ' selected' : ''}>${t.label}</option>`
        ).join('');
        typeSelect = `
            <label class="form-label">
                <span>Type</span>
                <select name="type">${opts}</select>
            </label>`;
    }

    return `
        <form method="POST">
            <input type="hidden" name="id" value="${event.id}"/>
            ${typeSelect}
            <label class="form-label">
                <span>Title</span>
                <input type="text" name="title" value="${event.title || ''}" required autocomplete="off"/>
            </label>
            <div class="form-row">
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>Start Date</span>
                    <input type="text" name="date" value="${dateStr}" data-datepicker="date"/>
                </label>
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>Start Time</span>
                    <input type="text" name="startTime" value="${startTime}" data-datepicker="time"/>
                </label>
            </div>
            <div class="form-row">
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>End Date</span>
                    <input type="text" name="endDate" value="${endDateStr}" data-datepicker="date"/>
                </label>
                <label class="form-label" style="flex:0 0 auto;min-width:0">
                    <span>End Time</span>
                    <input type="text" name="endTime" value="${endTime}" data-datepicker="time"/>
                </label>
            </div>
            <label class="form-label">
                <span>Description</span>
                <textarea name="description" rows="3" placeholder="Optional description">${event.description || ''}</textarea>
            </label>
        </form>`;
}

// ── DatePicker helper ───────────────────────────

/**
 * Find all `[data-datepicker]` inputs inside `root` and wrap each with a DatePicker.
 */
function initDatePickers(root) {
    root.querySelectorAll('[data-datepicker]').forEach(input => {
        new DatePicker(input, {
            type: input.dataset.datepicker,   // 'date' | 'time'
            value: input.value,
        });
    });
}

/**
 * Find all `select[name="type"]` inside `root` and wrap each with a Combobox.
 */
function initComboboxes(root) {
    root.querySelectorAll('select[name="type"]').forEach(sel => {
        new Combobox(sel);
    });
}

// ── CRUD Installer ──────────────────────────────

/**
 * Install CRUD capabilities onto a CalendarView context.
 *
 * @param {Object} ctx — context bridge from CalendarView
 *   ctx.razyui          — razyui instance
 *   ctx.config          — merged config (contains `crud`)
 *   ctx.events          — mutable events array
 *   ctx.render          — re-render function
 *   ctx.root            — root DOM element
 *   ctx.popup           — popup DOM element
 *   ctx.hidePopup       — hide popup function
 *   ctx.addEvent(ev)    — add event to store
 *   ctx.removeEvent(id) — remove event from store
 *   ctx.setEvents(evs)  — replace all events
 *   ctx.fireCallback(name, ...args) — fire user callback
 */
export function installCrud(ctx) {
    const razyui = ctx.razyui;
    const crudCfg = typeof ctx.config.crud === 'object' ? ctx.config.crud : {};


    // ── Resolve URLs with :id placeholder ──
    function resolveUrl(template, id) {
        if (!template) return '';
        return template.replace(':id', encodeURIComponent(id));
    }

    // ── Get event type plugin ──
    function getEventTypePlugin(type) {
        if (!type || !crudCfg.eventTypes?.length) return null;
        return crudCfg.eventTypes.find(t => t.type === type) || null;
    }

    // ── Build content for popup ──
    function buildPopupContent(event, mode, date, endDate) {
        let html;

        // Check for event-type plugin renderer first
        const eventType = event?.type || null;
        const plugin = getEventTypePlugin(eventType);

        if (plugin?.renderContent) {
            html = plugin.renderContent(event, mode);
        } else if (mode === 'add' && typeof crudCfg.renderAddContent === 'function') {
            html = crudCfg.renderAddContent(date, ctx, endDate);
        } else if (mode === 'edit' && typeof crudCfg.renderEditContent === 'function') {
            html = crudCfg.renderEditContent(event, ctx);
        } else if (mode === 'add') {
            html = defaultAddContent(date, crudCfg, endDate);
        } else {
            html = defaultEditContent(event, crudCfg);
        }

        // Wrap in element if string — unwrap to raw HTMLElement for Dialog
        let contentEl;
        if (typeof html === 'string') {
            contentEl = razyui.el('div', { innerHTML: html })[0];
        } else if (html && html[0] instanceof HTMLElement) {
            contentEl = html[0];
        } else {
            contentEl = html;
        }

        // Apply transform hook
        if (typeof crudCfg.transformContent === 'function') {
            crudCfg.transformContent(contentEl, event, mode);
        }

        return contentEl;
    }

    // ── Show Add Event Dialog ──
    async function showAddDialog(date, endDate) {
        const [Dialog] = await Promise.all([razyui.load('Dialog'), razyui.load('DatePicker'), razyui.load('Combobox')]);
        const content = buildPopupContent(null, 'add', date, endDate);

        const formConfig = {
            url: crudCfg.addUrl || '',
            method: 'POST',
            headers: crudCfg.headers || {},
            onValidation(data, formCtrl) {
                if (typeof crudCfg.onBeforeAdd === 'function') {
                    return crudCfg.onBeforeAdd(data, formCtrl);
                }
            },
            onSuccess(data, response) {
                // Add event to local calendar store
                const newEvent = data?.event || data;
                if (newEvent) {
                    ctx.addEvent(newEvent);
                }
                if (typeof crudCfg.onAfterAdd === 'function') {
                    crudCfg.onAfterAdd(newEvent, response);
                }
            },
            onError(errors, response) {
                if (typeof crudCfg.onError === 'function') {
                    crudCfg.onError(errors, response);
                }
            },
        };

        Dialog.open({
            title: 'Add Event',
            content,
            size: crudCfg.dialogSize || 'md',
            form: crudCfg.addUrl ? formConfig : false,
            closable: true,
            buttons: crudCfg.addUrl
                ? [
                    { text: 'Cancel', role: 'cancel' },
                    { text: 'Create', role: 'confirm', color: 'accent' },
                ]
                : [
                    { text: 'Cancel', role: 'cancel' },
                    {
                        text: 'Create', color: 'accent',
                        async action(ctrl) {
                            const form = ctrl.dialog?.querySelector?.('form') ||
                                         ctrl.body?.querySelector?.('form');
                            if (!form) return;
                            const formData = new FormData(form);
                            const data = Object.fromEntries(formData);

                            // await supports async AJAX in onBeforeAdd
                            if (typeof crudCfg.onBeforeAdd === 'function') {
                                const result = await crudCfg.onBeforeAdd(data, ctrl);
                                if (result === false) return false;
                            }

                            // Build local event from form data
                            const dateVal = data.date || date.toISOString().split('T')[0];
                            const endDateVal = data.endDate || dateVal;
                            const startTime = data.startTime || '00:00';
                            const endTime = data.endTime || '01:00';
                            const newEvent = {
                                title: data.title || 'Untitled',
                                start: new Date(`${dateVal}T${startTime}`),
                                end: new Date(`${endDateVal}T${endTime}`),
                                type: data.type || undefined,
                                description: data.description || '',
                                color: getEventTypePlugin(data.type)?.color || undefined,
                            };

                            ctx.addEvent(newEvent);

                            if (typeof crudCfg.onAfterAdd === 'function') {
                                await crudCfg.onAfterAdd(newEvent, null);
                            }
                        },
                    },
                ],
            onOpen(ctrl) {
                // Initialise DatePicker components on date/time inputs
                const dialogEl = ctrl.dialog || ctrl.body;
                if (dialogEl) {
                    initDatePickers(dialogEl);
                    initComboboxes(dialogEl);
                }

                // Focus title input
                const titleInput = ctrl.dialog?.querySelector?.('input[name="title"]') ||
                                   ctrl.body?.querySelector?.('input[name="title"]');
                if (titleInput) {
                    requestAnimationFrame(() => titleInput.focus());
                }

                // Event type change → swap plugin content
                const typeSelect = ctrl.dialog?.querySelector?.('select[name="type"]') ||
                                   ctrl.body?.querySelector?.('select[name="type"]');
                if (typeSelect && crudCfg.eventTypes?.length) {
                    razyui(typeSelect).on('change', () => {
                        const plugin = getEventTypePlugin(typeSelect.value);
                        if (plugin?.renderContent) {
                            const newContent = plugin.renderContent(null, 'add');
                            if (typeof newContent === 'string') {
                                ctrl.setContent(razyui.el('div', { innerHTML: newContent })[0]);
                            } else {
                                ctrl.setContent(newContent instanceof HTMLElement ? newContent : newContent?.[0] || newContent);
                            }
                        }
                    });
                }
            },
        });
    }

    // ── Show Edit Event Dialog ──
    async function showEditDialog(event) {
        const [Dialog] = await Promise.all([razyui.load('Dialog'), razyui.load('DatePicker'), razyui.load('Combobox')]);
        const content = buildPopupContent(event, 'edit', event.start);

        const formConfig = {
            url: resolveUrl(crudCfg.editUrl, event.id),
            method: 'PUT',
            headers: crudCfg.headers || {},
            onValidation(data, formCtrl) {
                if (typeof crudCfg.onBeforeEdit === 'function') {
                    return crudCfg.onBeforeEdit(data, formCtrl);
                }
            },
            onSuccess(data, response) {
                const updated = data?.event || data;
                if (updated) {
                    // Remove old, add updated
                    ctx.removeEvent(event.id);
                    ctx.addEvent({ ...event, ...updated });
                }
                if (typeof crudCfg.onAfterEdit === 'function') {
                    crudCfg.onAfterEdit(updated, response);
                }
            },
            onError(errors, response) {
                if (typeof crudCfg.onError === 'function') {
                    crudCfg.onError(errors, response);
                }
            },
        };

        Dialog.open({
            title: 'Edit Event',
            content,
            size: crudCfg.dialogSize || 'md',
            form: crudCfg.editUrl ? formConfig : false,
            closable: true,
            buttons: crudCfg.editUrl
                ? [
                    { text: 'Cancel', role: 'cancel' },
                    { text: 'Save', role: 'confirm', color: 'accent' },
                ]
                : [
                    { text: 'Cancel', role: 'cancel' },
                    {
                        text: 'Save', color: 'accent',
                        async action(ctrl) {
                            const form = ctrl.dialog?.querySelector?.('form') ||
                                         ctrl.body?.querySelector?.('form');
                            if (!form) return;
                            const formData = new FormData(form);
                            const data = Object.fromEntries(formData);

                            // await supports async AJAX in onBeforeEdit
                            if (typeof crudCfg.onBeforeEdit === 'function') {
                                const result = await crudCfg.onBeforeEdit(data, ctrl);
                                if (result === false) return false;
                            }

                            const dateVal = data.date || event.start.toISOString().split('T')[0];
                            const endDateVal = data.endDate || dateVal;
                            const startTime = data.startTime || '00:00';
                            const endTime = data.endTime || '01:00';
                            const updated = {
                                ...event,
                                title: data.title || event.title,
                                start: new Date(`${dateVal}T${startTime}`),
                                end: new Date(`${endDateVal}T${endTime}`),
                                type: data.type || event.type,
                                description: data.description ?? event.description,
                                color: getEventTypePlugin(data.type)?.color || event.color,
                            };

                            ctx.removeEvent(event.id);
                            ctx.addEvent(updated);

                            if (typeof crudCfg.onAfterEdit === 'function') {
                                await crudCfg.onAfterEdit(updated, null);
                            }
                        },
                    },
                ],
            onOpen(ctrl) {
                const dialogEl = ctrl.dialog || ctrl.body;
                if (dialogEl) {
                    initDatePickers(dialogEl);
                    initComboboxes(dialogEl);
                }
            },
        });
    }

    // ── Loading helpers ──

    /**
     * Find the DOM element for an event by its id.
     * @param {string} id
     * @returns {HTMLElement|null}
     */
    function findEventEl(id) {
        return ctx.root.querySelector(`[data-cal-event-id="${id}"]`);
    }

    /**
     * Toggle the `is-loading` class on the event DOM element.
     * @param {string} id
     * @param {boolean} loading
     */
    function setEventLoading(id, loading) {
        const el = findEventEl(id);
        if (el) el.classList.toggle('is-loading', loading);
    }

    // ── Delete Event (with confirmation) ──
    async function deleteEvent(event) {
        const Dialog = await razyui.load('Dialog');

        if (typeof crudCfg.onBeforeDelete === 'function') {
            const result = await crudCfg.onBeforeDelete(event);
            if (result === false) return;
        }

        const confirmed = await Dialog.confirm(
            'Delete Event',
            `Are you sure you want to delete "${event.title}"?`,
            { size: 'sm' }
        );

        if (!confirmed) return;

        if (crudCfg.deleteUrl) {
            // Show loading on the event chip/bar while waiting for server
            setEventLoading(event.id, true);
            try {
                const url = resolveUrl(crudCfg.deleteUrl, event.id);
                const response = await fetch(url, {
                    method: 'DELETE',
                    headers: {
                        'Content-Type': 'application/json',
                        ...(crudCfg.headers || {}),
                    },
                });
                if (!response.ok) {
                    setEventLoading(event.id, false);
                    const errData = await response.json().catch(() => ({}));
                    if (typeof crudCfg.onError === 'function') {
                        crudCfg.onError(errData, response);
                    }
                    return;
                }
                const data = await response.json().catch(() => ({}));
                ctx.removeEvent(event.id);
                if (typeof crudCfg.onAfterDelete === 'function') {
                    crudCfg.onAfterDelete(event, data);
                }
            } catch (err) {
                setEventLoading(event.id, false);
                if (typeof crudCfg.onError === 'function') {
                    crudCfg.onError({ message: err.message }, null);
                }
            }
        } else {
            // Local-only delete
            ctx.removeEvent(event.id);
            if (typeof crudCfg.onAfterDelete === 'function') {
                crudCfg.onAfterDelete(event, null);
            }
        }

        ctx.hidePopup();
    }

    // ── Attach to context ──

    /** Show add dialog for a given date slot. */
    ctx.showAddDialog = showAddDialog;

    /** Show edit dialog for an event. */
    ctx.showEditDialog = showEditDialog;

    /** Delete an event with confirmation. */
    ctx.deleteEvent = deleteEvent;

    /** Flag to indicate CRUD is installed. */
    ctx._crudInstalled = true;
}

// ── Enhanced popup builder (replaces default showPopup) ─────────

/**
 * Build an enhanced popup with Edit & Delete buttons when CRUD is installed.
 *
 * @param {Object} ctx       — CRUD context (razyui, config, popup, root, hidePopup, etc.)
 * @param {Object} ev        — normalised event
 * @param {HTMLElement} anchorEl
 * @returns {AbortController}
 */
export function showCrudPopup(ctx, ev, anchorEl) {
    const razyui = ctx.razyui;
    const popup = ctx.popup;
    const root = ctx.root;
    const hidePopupFn = () => ctx.hidePopup();
    const crudCfg = typeof ctx.config.crud === 'object' ? ctx.config.crud : {};

    // Import helpers for date formatting
    const startDate = ev.start;
    const endDate = ev.end;
    const sameD = startDate.getFullYear() === endDate.getFullYear() &&
                  startDate.getMonth() === endDate.getMonth() &&
                  startDate.getDate() === endDate.getDate();

    const MONTHS_SHORT = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const WEEKDAYS_SHORT = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    const pad = (n) => String(n).padStart(2, '0');
    const formatTime = (d) => `${pad(d.getHours())}:${pad(d.getMinutes())}`;

    const dateStr = sameD
        ? `${WEEKDAYS_SHORT[startDate.getDay()]}, ${MONTHS_SHORT[startDate.getMonth()]} ${startDate.getDate()}, ${startDate.getFullYear()}`
        : `${MONTHS_SHORT[startDate.getMonth()]} ${startDate.getDate()} – ${MONTHS_SHORT[endDate.getMonth()]} ${endDate.getDate()}, ${endDate.getFullYear()}`;
    const timeStr = sameD
        ? `${formatTime(startDate)} – ${formatTime(endDate)}`
        : `${WEEKDAYS_SHORT[startDate.getDay()]} ${formatTime(startDate)} – ${WEEKDAYS_SHORT[endDate.getDay()]} ${formatTime(endDate)}`;

    const $popup = razyui(popup);
    $popup.html('');

    // Color bar
    const bar = razyui.el('div', { className: 'cal-popup-bar' });
    PART.POPUP_BAR.apply(bar);
    bar.css('background', ev.color);
    $popup.append(bar[0]);

    // Action buttons row (close + edit + delete)
    const dom = razyui.spell(
        'div.cal-popup-actions(button.cal-popup-action-btn,button.cal-popup-action-btn.cal-popup-action-danger,button.cal-popup-close)',
        true
    );
    const actions = dom[0];
    PART.POPUP_ACTIONS.apply(actions);
    const btns = dom.find('button');

    const editBtn = btns[0];
    PART.POPUP_ACTION_BTN.apply(editBtn);
    editBtn.type = 'button';
    razyui(editBtn).html(ICON_EDIT);
    editBtn.title = 'Edit event';
    editBtn.dataset.calAction = 'crud-edit';

    const deleteBtn = btns[1];
    PART.POPUP_ACTION_BTN.apply(deleteBtn);
    deleteBtn.type = 'button';
    razyui(deleteBtn).html(ICON_DELETE);
    deleteBtn.title = 'Delete event';
    deleteBtn.dataset.calAction = 'crud-delete';

    const closeBtn = btns[2];
    PART.POPUP_CLOSE.apply(closeBtn);
    closeBtn.type = 'button';
    razyui(closeBtn).html(ICON_CLOSE);
    closeBtn.dataset.calAction = 'popup-close';

    $popup.append(actions);

    // Body
    const bodyDom = razyui.spell(
        'div.cal-popup-body(div.cal-popup-title,div.cal-popup-date,div.cal-popup-time)',
        true
    );
    const body = bodyDom[0];
    PART.POPUP_BODY.apply(body);
    PART.POPUP_TITLE.apply(bodyDom.find('.cal-popup-title'));
    PART.POPUP_DATE.apply(bodyDom.find('.cal-popup-date'));
    PART.POPUP_TIME.apply(bodyDom.find('.cal-popup-time'));

    // Event type badge
    if (ev.type) {
        const plugin = crudCfg.eventTypes?.find(t => t.type === ev.type);
        if (plugin) {
            const badge = razyui.el('span', { className: 'cal-popup-type-badge', textContent: plugin.label });
            badge.css('--badge-color', plugin.color || ev.color);
            body.insertBefore(badge[0], body.firstChild);
        }
    }

    bodyDom.find('.cal-popup-title').text(ev.title);
    bodyDom.find('.cal-popup-date').text(dateStr);
    bodyDom.find('.cal-popup-time').text(timeStr);

    if (ev.description) {
        const desc = razyui.el('div', { className: 'cal-popup-description', textContent: ev.description });
        razyui(body).append(desc[0]);
    }

    $popup.append(body);

    // ── Show & position ──
    popup.hidden = false;

    const rootRect = root.getBoundingClientRect();
    const anchorRect = anchorEl.getBoundingClientRect();

    // Minimum top = below the calendar header so the popup never covers it
    const calHeader = razyui(root).find('.cal-header')[0];
    const minTop = calHeader ? calHeader.getBoundingClientRect().bottom - rootRect.top + 4 : 4;

    let left = anchorRect.left - rootRect.left + anchorRect.width + 8;
    let top = anchorRect.top - rootRect.top;

    const pw = popup.offsetWidth;
    const ph = popup.offsetHeight;

    if (left + pw > rootRect.width) {
        left = anchorRect.left - rootRect.left - pw - 8;
    }
    if (left < 0) {
        left = Math.max(4, (rootRect.width - pw) / 2);
    }
    if (top + ph > rootRect.height) {
        top = rootRect.height - ph - 4;
    }
    if (top < minTop) top = minTop;

    $popup.css({ left: `${left}px`, top: `${top}px` });

    // ── Button handlers ──
    razyui(editBtn).on('click', (e) => {
        e.stopPropagation();
        hidePopupFn();
        ctx.showEditDialog(ev);
    });

    razyui(deleteBtn).on('click', (e) => {
        e.stopPropagation();
        ctx.deleteEvent(ev);
    });

    razyui(closeBtn).on('click', (e) => {
        e.stopPropagation();
        hidePopupFn();
    });

    // Close on scroll / resize
    const ac = new AbortController();
    const hide = () => hidePopupFn();
    razyui(document).on('scroll', hide, { capture: true, passive: true, signal: ac.signal });
    razyui(window).on('resize', hide, { passive: true, signal: ac.signal });

    return ac;
}

/**
 * Build an "Add event" button for the calendar header.
 *
 * @param {Object} razyui
 * @returns {HTMLElement}
 */
export function buildAddButton(razyui) {
    const btn = razyui.el('button', {
        type: 'button',
        className: 'cal-btn cal-btn-add',
        innerHTML: ICON_ADD,
        title: 'Add event',
        'data-cal-action': 'crud-add',
    });
    return btn;
}

export default installCrud;
