/**
 * @fileoverview CalendarView events — centralized event binding & navigation.
 * @module module/CalendarView/events
 */

import { startOfDay, addDays } from './helpers.js';
import { NOW_LINE_INTERVAL } from './constants.js';
import razyui from '../../index.js';

// ── Navigation helpers ──────────────────────────

/**
 * Navigate to today.
 *
 * @param {Function} setState
 * @param {Function} fireNavigate
 */
export function goToday(setState, fireNavigate) {
    setState({ date: startOfDay(new Date()) });
    fireNavigate();
}

/**
 * Navigate to the previous period.
 *
 * @param {object}   stateRef
 * @param {Function} setState
 * @param {Function} fireNavigate
 */
export function goPrev(stateRef, setState, fireNavigate) {
    const date = stateRef.date;
    const view = stateRef.view;
    if (view === 'month') {
        setState({ date: new Date(date.getFullYear(), date.getMonth() - 1, 1) });
    } else if (view === 'week') {
        setState({ date: addDays(date, -7) });
    } else {
        setState({ date: addDays(date, -1) });
    }
    fireNavigate();
}

/**
 * Navigate to the next period.
 *
 * @param {object}   stateRef
 * @param {Function} setState
 * @param {Function} fireNavigate
 */
export function goNext(stateRef, setState, fireNavigate) {
    const date = stateRef.date;
    const view = stateRef.view;
    if (view === 'month') {
        setState({ date: new Date(date.getFullYear(), date.getMonth() + 1, 1) });
    } else if (view === 'week') {
        setState({ date: addDays(date, 7) });
    } else {
        setState({ date: addDays(date, 1) });
    }
    fireNavigate();
}

// ── Callbacks ───────────────────────────────────

/**
 * Fire `onSlotClick` if configured.
 *
 * @param {object}   config
 * @param {object}   stateRef
 * @param {object}   ctx — `this` context (the CalendarView instance)
 * @param {Date}     date
 */
export function fireSlotClick(config, stateRef, ctx, date) {
    if (typeof config.onSlotClick === 'function') {
        config.onSlotClick.call(ctx, date, stateRef.view);
    }
}

/**
 * Fire `onEventClick` if configured.
 *
 * @param {object} config
 * @param {object} ctx
 * @param {object} ev
 */
export function fireEventClick(config, ctx, ev) {
    if (typeof config.onEventClick === 'function') {
        config.onEventClick.call(ctx, { ...ev });
    }
}

/**
 * Fire `onNavigate` if configured.
 *
 * @param {object} config
 * @param {object} stateRef
 * @param {object} ctx
 */
export function fireNavigate(config, stateRef, ctx) {
    if (typeof config.onNavigate === 'function') {
        config.onNavigate.call(ctx, new Date(stateRef.date), stateRef.view);
    }
}

// ── Now-line timer ──────────────────────────────

/**
 * Start the 60-second interval that updates the current-time line.
 *
 * @param {HTMLElement} root
 * @param {object}      config
 * @param {object}      razyui
 * @returns {number} interval handle
 */
export function startNowLineTimer(root, config, razyui) {
    return setInterval(() => {
        const line = razyui(root).find('.cal-now-line')[0];
        if (line) {
            const now = new Date();
            const mins = now.getHours() * 60 + now.getMinutes();
            const startMin = (config.dayStartHour || 0) * 60;
            const endMin = (config.dayEndHour || 24) * 60;
            const pct = ((mins - startMin) / (endMin - startMin)) * 100;
            razyui(line).css('top', `${razyui.clamp(pct, 0, 100)}%`);
        }
    }, NOW_LINE_INTERVAL);
}

// ── Delegated event binding ─────────────────────

/**
 * Bind delegated click events on the header container.
 *
 * @param {HTMLElement} header
 * @param {object}     callbacks — { goToday, goPrev, goNext, setView }
 */
export function bindHeaderEvents(header, callbacks) {
    razyui(header).on('click', (e) => {
        const target = e.target.closest('[data-cal-action]');
        if (!target) return;
        const action = target.dataset.calAction;
        if (action === 'today') callbacks.goToday();
        else if (action === 'prev') callbacks.goPrev();
        else if (action === 'next') callbacks.goNext();
        else if (action === 'view') callbacks.setView(target.dataset.calView);
    });
}

/**
 * Bind delegated click events on the calendar body.
 *
 * Handles event-bar / chip / block clicks, "+N more" toggles,
 * month-cell slot clicks and time-grid cell slot clicks.
 *
 * @param {HTMLElement} body
 * @param {Array}       events — normalised event objects (need `.id`)
 * @param {object}      callbacks — { showPopup, fireEventClick, fireSlotClick }
 */
export function bindCalendarBodyEvents(body, getEvents, callbacks) {
    razyui(body).on('click', (e) => {
        // Event bar / chip / block
        const eventEl = e.target.closest('[data-cal-event-id]');
        if (eventEl) {
            e.stopPropagation();
            const ev = getEvents().find(x => x.id === eventEl.dataset.calEventId);
            if (ev) {
                callbacks.showPopup(ev, eventEl);
                callbacks.fireEventClick(ev);
            }
            return;
        }

        // "+N more" toggle
        const more = e.target.closest('.cal-event-more');
        if (more) {
            e.stopPropagation();
            const cell = more.closest('.cal-month-cell');
            if (cell) {
                const $cell = razyui(cell);
                $cell.toggleClass('is-expanded');
                const expanded = $cell.hasClass('is-expanded');
                $cell.find('.cal-event-chip.is-overflow').each(c => razyui(c).toggleClass('cal-event-chip-hidden', !expanded));
                const count = more.dataset.calOverflowCount;
                razyui(more).text(expanded ? 'Show less' : `+${count} more`);
            }
            return;
        }

        // Month cell → slot click
        const monthCell = e.target.closest('.cal-month-cell');
        if (monthCell && monthCell.dataset.calDate) {
            callbacks.fireSlotClick(new Date(Number(monthCell.dataset.calDate)));
            return;
        }

        // Time-grid cell → slot click
        const timeCell = e.target.closest('.cal-tg-cell');
        if (timeCell && timeCell.dataset.calDate) {
            callbacks.fireSlotClick(new Date(Number(timeCell.dataset.calDate)));
            return;
        }
    });
}

/**
 * Bind delegated click on the popup for the close button.
 *
 * Survives `popup.innerHTML` rebuilds because the listener is on
 * the persistent popup element itself.
 *
 * @param {HTMLElement} popup
 * @param {Function}    hidePopupFn
 */
export function bindPopupClose(popup, hidePopupFn) {
    razyui(popup).on('click', (e) => {
        const closeBtn = e.target.closest('[data-cal-action="popup-close"]');
        if (closeBtn) {
            e.stopPropagation();
            hidePopupFn();
        }
    });
}
