/**
 * @fileoverview CalendarView reactive state creation.
 * @module module/CalendarView/state
 */

import { startOfDay } from './helpers.js';

/**
 * Create reactive state for CalendarView.
 *
 * @param {Function} stateFn — `razyui.state`
 * @param {object}   cfg     — merged config
 * @returns {{ stateRef: object, setState: Function, stateSet: object }}
 */
export function createState(stateFn, cfg) {
    const stateSet = stateFn({
        view: cfg.view,
        date: startOfDay(cfg.date),
    });
    const [stateRef, setState] = stateSet;
    return { stateRef, setState, stateSet };
}
